const text = (value) => String(value ?? '').trim();
const dateOnly = (value) => text(value).slice(0, 10);
const keys = [];
for (const item of items) {
  const invoiceId = text(item.json?.invoice_id);
  const reminderType = text(item.json?.reminder_type);
  const createdDate = dateOnly(item.json?.created_at);
  if (invoiceId && reminderType && createdDate) keys.push(`${invoiceId}:${reminderType}:${createdDate}`);
}
return [{ json: { existing_send_keys: [...new Set(keys)] } }];

const TEST_CASE = 'due_soon';
const cases = {
  due_soon: { invoice_id: 'INV-MOCK-DUE', client_name: 'Mock Due Customer', client_email: 'mock.due@example.com', amount: 1200, currency: 'USD', issue_date: '2026-05-10', due_offset_days: 2, status: 'sent', reminders_sent: 0, last_reminder_at: '', paid_at: '', processed: 'FALSE' },
  overdue: { invoice_id: 'INV-MOCK-OVERDUE', client_name: 'Mock Overdue Customer', client_email: 'mock.overdue@example.com', amount: 850, currency: 'USD', issue_date: '2026-04-25', due_offset_days: -3, status: 'overdue', reminders_sent: 1, last_reminder_at: '2026-05-18', paid_at: '', processed: 'FALSE' },
  escalation: { invoice_id: 'INV-MOCK-ESCALATE', client_name: 'Mock Escalation Customer', client_email: 'mock.escalate@example.com', amount: 2200, currency: 'USD', issue_date: '2026-03-28', due_offset_days: -22, status: 'overdue', reminders_sent: 3, last_reminder_at: '2026-05-15', paid_at: '', processed: 'FALSE' },
  invalid_contact: { invoice_id: 'INV-MOCK-INVALID', client_name: 'Mock Invalid Customer', client_email: '', amount: 640, currency: 'USD', issue_date: '2026-05-01', due_offset_days: -1, status: 'sent', reminders_sent: 0, last_reminder_at: '', paid_at: '', processed: 'FALSE' },
  paid: { invoice_id: 'INV-MOCK-PAID', client_name: 'Mock Paid Customer', client_email: 'mock.paid@example.com', amount: 430, currency: 'USD', issue_date: '2026-04-20', due_offset_days: -8, status: 'paid', reminders_sent: 0, last_reminder_at: '2026-05-05', paid_at: '2026-05-10', processed: 'FALSE' },
  not_due: { invoice_id: 'INV-MOCK-NOTDUE', client_name: 'Mock Future Customer', client_email: 'mock.future@example.com', amount: 310, currency: 'USD', issue_date: '2026-05-18', due_offset_days: 16, status: 'sent', reminders_sent: 0, last_reminder_at: '', paid_at: '', processed: 'FALSE' }
};
const selected = cases[TEST_CASE] || cases.due_soon;
const due = new Date();
due.setUTCDate(due.getUTCDate() + Number(selected.due_offset_days || 0));
return [{ json: { ...selected, due_date: due.toISOString().slice(0, 10), row_number: 2 } }];

const today = new Date().toISOString().slice(0, 10);
const todayDate = new Date(`${today}T00:00:00Z`);
let contextItems = [];
try { contextItems = $('Seed reminder send context').all(); } catch (_) { contextItems = []; }
const existingKeys = new Set((contextItems[0]?.json?.existing_send_keys || []).map(String));
const text = (value) => String(value ?? '').trim();
const number = (value) => Number(value || 0);
const dateOnly = (value) => text(value).slice(0, 10);
const validEmail = (value) => text(value).includes('@') && text(value).includes('.');
const closedStatuses = new Set(['paid', 'cancelled', 'void', 'refunded']);
const hasSignal = (row) => ['invoice_id', 'due_date', 'client_name', 'client_email', 'amount', 'status'].some((field) => text(row[field]));
const out = [];
let skipped = 0;
for (const [index, item] of items.entries()) {
  const row = item.json || {};
  if (!hasSignal(row)) { skipped += 1; continue; }
  const invoiceId = text(row.invoice_id);
  const clientName = text(row.client_name || row.customer_name);
  const clientEmail = text(row.client_email || row.customer_email);
  const status = text(row.status || 'sent').toLowerCase();
  const dueDateText = dateOnly(row.due_date);
  const dueDate = new Date(`${dueDateText}T00:00:00Z`);
  const remindersSent = number(row.reminders_sent ?? row.reminder_count);
  if (closedStatuses.has(status)) { skipped += 1; continue; }
  const sourceRowNumber = row.row_number ?? row.rowNumber ?? row.__rowNumber ?? row._rowNumber ?? index + 2;
  if (!invoiceId || !dueDateText || Number.isNaN(dueDate.getTime())) {
    const reminderType = 'manager_review';
    const key = `${invoiceId || 'missing_invoice_id'}:${reminderType}:${today}`;
    if (existingKeys.has(key)) { skipped += 1; continue; }
    existingKeys.add(key);
    out.push({ json: { ...row, has_work: true, processed_at: new Date().toISOString(), as_of_date: today, source_row_number: sourceRowNumber, invoice_id: invoiceId || 'missing_invoice_id', client_name: clientName, client_email: clientEmail, reminder_type: reminderType, needs_manager_review: true, reason: 'missing_invoice_id_or_due_date', queue_status: 'manager_review_required', previous_status: status, new_status: 'review_required', reminders_sent_before: remindersSent, reminders_sent_after: remindersSent, days_overdue_value: '', days_to_due_value: '', message: 'Invoice data is incomplete and must be reviewed before a reminder is prepared.', audit_message: 'Invoice routed to manager review: missing_invoice_id_or_due_date' } });
    continue;
  }
  if (dateOnly(row.last_reminder_at) === today) { skipped += 1; continue; }
  const diffDays = Math.ceil((dueDate.getTime() - todayDate.getTime()) / 86400000);
  if (diffDays > 3) { skipped += 1; continue; }
  let reminderType = diffDays >= 0 ? 'due_soon' : 'overdue';
  let needsManagerReview = false;
  let reason = diffDays < 0 ? `${Math.abs(diffDays)} days overdue` : `due in ${diffDays} days`;
  if (!validEmail(clientEmail)) { reminderType = 'invalid_contact'; needsManagerReview = true; reason = 'missing_client_email'; }
  if (diffDays < -14 || remindersSent >= 3) { reminderType = 'manager_review'; needsManagerReview = true; reason = 'severe_overdue_or_reminder_limit_reached'; }
  const key = `${invoiceId}:${reminderType}:${today}`;
  if (existingKeys.has(key)) { skipped += 1; continue; }
  existingKeys.add(key);
  const amount = number(row.amount).toFixed(2);
  const message = needsManagerReview
    ? `Invoice ${invoiceId} requires manager review before any customer reminder is sent. Reason: ${reason}.`
    : `Hello ${clientName || 'there'}, this is a reminder for invoice ${invoiceId} (${text(row.currency) || 'USD'} ${amount}) due on ${dueDateText}.`;
  const newStatus = needsManagerReview ? (reminderType === 'manager_review' ? 'escalated' : 'review_required') : (diffDays < 0 ? 'overdue' : status || 'sent');
  const countAfter = needsManagerReview ? remindersSent : remindersSent + 1;
  out.push({ json: { ...row, has_work: true, processed_at: new Date().toISOString(), as_of_date: today, source_row_number: sourceRowNumber, invoice_id: invoiceId, client_name: clientName, client_email: clientEmail, amount: number(row.amount), currency: text(row.currency || 'USD'), due_date: dueDateText, reminder_type: reminderType, needs_manager_review: needsManagerReview, reason, queue_status: needsManagerReview ? 'manager_review_required' : 'queued_for_review', previous_status: status, new_status: newStatus, reminders_sent_before: remindersSent, reminders_sent_after: countAfter, days_overdue_value: diffDays < 0 ? Math.abs(diffDays) : '', days_to_due_value: diffDays >= 0 ? diffDays : '', message, audit_message: needsManagerReview ? `Invoice routed to manager review: ${reason}` : `Reminder draft queued: ${reminderType}` } });
}
if (out.length === 0) {
  return [{ json: { has_work: false, control_event: 'no_invoice_reminder_work', status: 'ok_empty', reason: 'No invoices need reminders today.', checked_at: new Date().toISOString(), source_items_count: items.length, skipped_count: skipped } }];
}
return out;
